<?php
// GLV Global Food Services — Auto-Deployer
// Upload to public_html/glvglobalfoodservices/ and visit in browser once.
// It will deploy all site files and self-delete.
set_time_limit(120);
$files = [
    'index.html' => '',
    'animales-vivos.html' => '',
    'frutas.html' => '',
    'huevo-proteinas.html' => '',
    'coco-aceites.html' => '',
    'granos-cereales.html' => '',
    'comercio-internacional.html' => '',
    'send-email.php' => '',
    '.htaccess' => ''
];
$base = __DIR__;
$ok = []; $fail = [];
foreach ($files as $name => $b64) {
    $gz  = base64_decode($b64);
    $raw = gzdecode($gz);
    $dest = $base . '/' . $name;
    $dir  = dirname($dest);
    if (!is_dir($dir)) @mkdir($dir, 0755, true);
    if (file_put_contents($dest, $raw) !== false) $ok[] = $name;
    else $fail[] = $name;
}
@unlink(__FILE__);
header('Content-Type: text/plain; charset=UTF-8');
echo '=== GLV DEPLOY ===
';
foreach ($ok as $f)   echo 'OK   ' . $f . '
';
foreach ($fail as $f) echo 'FAIL ' . $f . '
';
echo '
Deployed ' . count($ok) . '/' . (count($ok)+count($fail)) . ' files.
';
echo 'Deployer self-deleted.
';
